/**
 * @fileoverview Progress constants.
 * @module module/Progress/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:   'progress',
    TRACK:  'progress-track',
    BAR:    'progress-bar',
    LABEL:  'progress-label',
});

export const DEFAULTS = Object.freeze({
    value: 0,           // 0-100
    size: 'md',
    variant: 'primary', // primary | success | warning | danger
    showLabel: false,
    striped: false,
    animated: false,
});

export const PART = defineParts('Progress', {
    ROOT:    { class: 'progress-container', aliases: ['root', 'container'] },
    TRACK:   { class: 'progress-track', aliases: ['track'] },
    BAR:     { class: 'progress-bar', aliases: ['bar'] },
    LABEL:   { class: 'progress-label', aliases: ['label'], tag: 'span' },
    SM_ROOT: { class: 'progress-container-sm', aliases: ['sm'] },
    LG_ROOT: { class: 'progress-container-lg', aliases: ['lg'] },
    SUCCESS: { class: 'progress-success', aliases: ['success'] },
    WARNING: { class: 'progress-warning', aliases: ['warning'] },
    DANGER:  { class: 'progress-danger', aliases: ['danger'] },
});

PART.ROOT.jit    = 'flex flex-col gap-[var(--pg-gap)] w-full';
PART.TRACK.jit   = 'relative w-full h-[var(--pg-h)] bg-[var(--pg-track-bg)] rounded-[var(--pg-radius)] overflow-hidden';
PART.BAR.jit     = 'h-full bg-[var(--pg-bar-bg)] rounded-[var(--pg-radius)] [transition:width_.3s_ease]';
PART.LABEL.jit   = 'text-[var(--pg-font-size)] fg-[var(--pg-label-color)] text-right [font-variant-numeric:tabular-nums]';
PART.SM_ROOT.jit = '[--pg-h:var(--pg-sm-h)] [--pg-font-size:var(--pg-sm-font-size)]';
PART.LG_ROOT.jit = '[--pg-h:var(--pg-lg-h)] [--pg-font-size:var(--pg-lg-font-size)]';
PART.SUCCESS.jit = '[--pg-bar-bg:var(--pg-success-bg)]';
PART.WARNING.jit = '[--pg-bar-bg:var(--pg-warning-bg)]';
PART.DANGER.jit  = '[--pg-bar-bg:var(--pg-danger-bg)]';
