/**
 * @fileoverview Progress component — modular entry point.
 * @module module/Progress
 */

import { default as razyui } from '../../index.js';
import { ProgressDef as DEF } from '../Progress.def.js';
import { DEFAULTS } from './constants.js';
import { setupDOM, cleanupDOM } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';

const Progress = class {
    #root    = null;
    #destroyed = false;
    #barEl   = null;
    #labelEl = null;
    #config  = {};
    #value   = 0;

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Progress: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#value  = this.#config.value;
        this.#init();
    }

    #init() {
        const { barEl, labelEl } = setupDOM(this.#root, this.#config);
        this.#barEl   = barEl;
        this.#labelEl = labelEl;
    }

    get value() { return this.#value; }
    set value(v) {
        const clamped = Math.min(100, Math.max(0, v));
        this.#value = clamped;
        this.#barEl[0].style.width = `${clamped}%`;
        this.#root[0].setAttribute('aria-valuenow', String(clamped));
        if (this.#labelEl) {
            this.#labelEl[0].textContent = `${Math.round(clamped)}%`;
        }
        emitEvent(this.#root[0], 'change', { value: clamped });
    }

    getControl() {
        const self = this;
        return {
            get value()    { return self.value; },
            set value(v)   { self.value = v; },
            get variant()  { return self.#config.variant; },
            set variant(v) { self.#config.variant = v; },
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        cleanupDOM(this.#root);
    }
};

export default Progress;
